&lt;ul class=&quot;mt3 pl4 t-14 featured-benefits__benefit-list&quot;&gt;
&lt;li class=&quot;featured-benefits__benefit&quot;&gt;$30.00 per hour + Overtime&lt;/li&gt;
&lt;li class=&quot;featured-benefits__benefit&quot;&gt;Medical insurance&lt;/li&gt;
&lt;li class=&quot;featured-benefits__benefit&quot;&gt;Dental insurance&lt;/li&gt;
&lt;li class=&quot;featured-benefits__benefit&quot;&gt;Vision insurance&lt;/li&gt;
&lt;li class=&quot;featured-benefits__benefit&quot;&gt;401(k)&lt;/li&gt;
&lt;li class=&quot;featured-benefits__benefit&quot;&gt;Disability insurance&lt;br&gt;&lt;br&gt;&lt;/li&gt;
&lt;/ul&gt;
